INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Bhopal', 'fee_structure', 'Fee Structure > Program: B.Tech ECE (Admission Year 2024). WARNING: These fees appear subsidized/waived and may not reflect general category fees.');
